import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Injectable, inject } from '@angular/core';
import { BehaviorSubject, Observable, finalize } from 'rxjs';
import { environment } from 'src/environments/environment';

@Injectable({
  providedIn: 'root',
})
export class ApiHttpService {
  private http = inject(HttpClient);

  readonly AppUrl: string = environment.apiUrl;
  readonly MaxUploadSize = 20480; // 20 MB => 1024 KB = 1 MB

  private loadingCount = 0;
  private loadingEmitScheduled = false;
  readonly loading$ = new BehaviorSubject<boolean>(false);

  private scheduleLoadingEmit(): void {
    if (this.loadingEmitScheduled) {
      return;
    }

    this.loadingEmitScheduled = true;
    Promise.resolve().then(() => {
      this.loadingEmitScheduled = false;
      this.loading$.next(this.loadingCount > 0);
    });
  }

  private setLoading(on: boolean): void {
    this.loadingCount += on ? 1 : -1;
    if (this.loadingCount < 0) {
      this.loadingCount = 0;
    }
    this.scheduleLoadingEmit();
  }

  private withLoading<T>(obs: Observable<T>): Observable<T> {
    this.setLoading(true);
    return obs.pipe(finalize(() => this.setLoading(false)));
  }

  ladeHeaders(filesVorhanden: boolean, bearerToken?: string): HttpHeaders {
    let headers = new HttpHeaders();

    if (bearerToken) {
      headers = headers.set('Authorization', `Bearer ${bearerToken}`);
    }

    if (!filesVorhanden) {
      headers = headers.set('Content-Type', 'application/json; charset=utf-8');
    }

    return headers;
  }

  get<T = unknown>(modul: string, param?: any, afterSlash?: boolean): Observable<T> {
    const headers = this.ladeHeaders(false);
    const query = this.buildQueryString(param);

    let url = `${this.AppUrl}${modul}`;
    if (!query) {
      url += '/';
    } else {
      if (afterSlash === true) {
        url += '/';
      }
      url += query;
    }

    return this.withLoading(this.http.get<T>(url, { headers }));
  }

  getURL<T = unknown>(url: string): Observable<T> {
    return this.withLoading(this.http.get<T>(url));
  }

  post<T = unknown>(modul: string, daten: any, _filesVorhanden?: boolean): Observable<T> {
    const isFD = typeof FormData !== 'undefined' && daten instanceof FormData;
    const headers = this.ladeHeaders(isFD);
    const url = `${this.AppUrl}${modul}/`;

    return this.withLoading(this.http.post<T>(url, daten, { headers }));
  }

  patch<T = unknown>(modul: string, id: any, daten: any, _filesVorhanden?: boolean): Observable<T> {
    const isFD = typeof FormData !== 'undefined' && daten instanceof FormData;
    const headers = this.ladeHeaders(isFD);

    const url = id !== ''
      ? `${this.AppUrl}${modul}/${id}/`
      : `${this.AppUrl}${modul}/`;

    return this.withLoading(this.http.patch<T>(url, daten, { headers }));
  }

  delete<T = unknown>(modul: string, id: any): Observable<T> {
    const headers = this.ladeHeaders(false);
    const url = `${this.AppUrl}${modul}/${id}/`;

    return this.withLoading(this.http.delete<T>(url, { headers }));
  }

  postBlob(modul: string, daten: any): Observable<Blob> {
    const isFD = typeof FormData !== 'undefined' && daten instanceof FormData;
    const headers = this.ladeHeaders(isFD).set('Accept', 'application/pdf');
    const url = `${this.AppUrl}${modul}/`;

    return this.withLoading(this.http.post(url, daten, {
      headers,
      responseType: 'blob',
    }));
  }

  getWithBearer<T = unknown>(modul: string, token: string): Observable<T> {
    const headers = this.ladeHeaders(false, token);
    const url = `${this.AppUrl}${modul}/`;

    return this.withLoading(this.http.get<T>(url, { headers }));
  }

  cleanupOrphanMedia(payload: {
    target?: 'all' | 'news' | 'homepage' | 'inventar' | 'einsatzberichte' | 'anwesenheitsliste';
    delete?: boolean;
    allow_missing_db?: boolean;
  }): Observable<any> {
    return this.post('files/cleanup-orphans', payload, false);
  }

  private buildQueryString(param?: Record<string, any>): string {
    if (!param || typeof param !== 'object') {
      return '';
    }

    let query = '';
    for (const prop in param) {
      if (Object.prototype.hasOwnProperty.call(param, prop)) {
        query += query === '' ? `?${prop}=${param[prop]}` : `&${prop}=${param[prop]}`;
      }
    }

    return query;
  }
}

import { Injectable, inject } from '@angular/core';
import { Router } from '@angular/router';
import { ApiHttpService } from './api-http.service';
import { UiMessageService } from './ui-message.service';

@Injectable({
  providedIn: 'root',
})
export class AuthSessionService {
  private api = inject(ApiHttpService);
  private router = inject(Router);
  private messages = inject(UiMessageService);

  abmelden(): void {
    this.api.post('auth/logout', null, false).subscribe({
      next: () => {
        this.clearSessionAndCookies();
        this.router.navigate(['/login']);
      },
      error: (error: any) => {
        this.errorAnzeigen(error);
      },
    });
  }

  errorAnzeigen(response: any): void {
    const errorObject = response?.error;

    if (errorObject && typeof errorObject === 'object') {
      const msg = Object.values(errorObject)
        .map((value) => String(value))
        .join('\n');

      if (msg !== '') {
        this.messages.erstelleMessage('error', msg);
      }
    }

    if (response?.status === 401) {
      this.clearSessionAndCookies();
      this.router.navigate(['/login']);
    }
  }

  private clearSessionAndCookies(): void {
    sessionStorage.clear();
    document.cookie.split('; ').forEach((cookie) => {
      const [name] = cookie.split('=');
      document.cookie = `${name}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;`;
    });
  }
}

import { Injectable } from '@angular/core';
import { AbstractControl } from '@angular/forms';

@Injectable({
  providedIn: 'root',
})
export class CollectionUtilsService {
  arraySortByKey(array: any[], key: any): any[] {
    array.sort((a: any, b: any) => (a[key] === b[key] ? 0 : +(a[key] > b[key]) || -1));
    return array;
  }

  arraySortByKeyDesc(array: any[], key: any): any[] {
    array.sort((a: any, b: any) => (a[key] === b[key] ? 0 : +(a[key] < b[key]) || -1));
    return array;
  }

  sucheArrayInArray(gesamtArray: any[], teilArray: any[], vergleichKey: string): any[] {
    const arrayNeu = [];
    for (let i = 0; i < gesamtArray.length; i += 1) {
      let count = 0;
      for (let x = 0; x < teilArray.length; x += 1) {
        if (gesamtArray[i][vergleichKey] === teilArray[x][vergleichKey]) {
          count += 1;
        }
      }
      if (count === 0) {
        arrayNeu.push(gesamtArray[i]);
      }
    }
    return arrayNeu;
  }

  sucheNumberArrayInObjectArray(gesamtArray: any[], teilArray: any[], gesamtArrayKey: string): any[] {
    const arrayNeu = [];
    for (let i = 0; i < gesamtArray.length; i += 1) {
      let count = 0;
      for (let x = 0; x < teilArray.length; x += 1) {
        if (gesamtArray[i][gesamtArrayKey] === teilArray[x]) {
          count += 1;
        }
      }
      if (count === 0) {
        arrayNeu.push(gesamtArray[i]);
      }
    }
    return arrayNeu;
  }

  vergleicheZweiArrays(array1: any[], array2: any[], vergleichKey: string): any[] {
    const arrayNeu = array1;
    for (let i = 0; i < array2.length; i += 1) {
      let count = 0;
      for (let x = 0; x < arrayNeu.length; x += 1) {
        if (array2[i][vergleichKey] === arrayNeu[x][vergleichKey]) {
          count += 1;
        }
      }
      if (count === 0) {
        arrayNeu.push(array2[i]);
      }
    }
    return arrayNeu;
  }

  addItemFromSelectToList(control: AbstractControl, arrayGesamt: any[], array: any[]): void {
    const selectedId = control.value;
    if (selectedId !== '0') {
      if (array.length > 0) {
        let count = 0;
        for (let i = 0; i < array.length; i += 1) {
          if (selectedId === array[i]) {
            count += 1;
          }
        }
        if (count === 0) {
          for (let i = 0; i < arrayGesamt.length; i += 1) {
            if (selectedId === arrayGesamt[i].pkid) {
              array.push({
                pkid: arrayGesamt[i].pkid,
                kuerzel: arrayGesamt[i].kuerzel,
                name: arrayGesamt[i].name,
              });
              arrayGesamt.splice(i, 1);
            }
          }
        }
      } else {
        for (let i = 0; i < arrayGesamt.length; i += 1) {
          if (selectedId === arrayGesamt[i].pkid) {
            array.push({
              pkid: arrayGesamt[i].pkid,
              kuerzel: arrayGesamt[i].kuerzel,
              name: arrayGesamt[i].name,
            });
            arrayGesamt.splice(i, 1);
          }
        }
      }

      control.setValue(0, { onlySelf: true });
      this.arraySortByKey(array, 'kuerzel');
    }
  }

  addItemFromListToSelect(pkid: string, arrayGesamt: any[], array: any[]): void {
    for (let i = 0; i < array.length; i += 1) {
      if (pkid === array[i].pkid) {
        arrayGesamt.push({ pkid: array[i].pkid, kuerzel: array[i].kuerzel, name: array[i].name });
        array.splice(i, 1);
      }
    }
    this.arraySortByKey(arrayGesamt, 'kuerzel');
  }

  addFeldInArray(arrayGesamt: any[], array: any[], feldName: string, joinKey: string): any[] {
    const map = new Map(arrayGesamt.map((item) => [item[joinKey], item[feldName]]));

    return array.map((item) => {
      const key = item[joinKey];
      if (map.has(key)) {
        return { ...item, [feldName]: map.get(key) };
      }
      return item;
    });
  }

  addAllFieldsToNumberArray(arrayGesamt: any[], array: any[]): any[] {
    const dataNew = [];
    for (let i = 0; i < array.length; i += 1) {
      const pkid = array[i];
      for (let x = 0; x < arrayGesamt.length; x += 1) {
        if (pkid === arrayGesamt[x].pkid) {
          dataNew.push(arrayGesamt[x]);
        }
      }
    }

    return dataNew;
  }
}

