import { AfterViewInit, ChangeDetectorRef, Component, OnInit, ViewChild, inject, QueryList, ViewChildren } from '@angular/core';
import { IMitglied } from 'src/app/_interface/mitglied';
import { ApiHttpService } from 'src/app/_service/api-http.service';
import { AuthSessionService } from 'src/app/_service/auth-session.service';
import { CollectionUtilsService } from 'src/app/_service/collection-utils.service';
import { NavigationService } from 'src/app/_service/navigation.service';
import { UiMessageService } from 'src/app/_service/ui-message.service';
import { ImrHeaderComponent } from '../imr-ui-library';
import { MatCardModule } from '@angular/material/card';
import { Router } from '@angular/router';
import { MatTabsModule } from '@angular/material/tabs';
import { AbstractControl, FormControl, FormGroup, FormsModule, ReactiveFormsModule, ValidatorFn, Validators } from '@angular/forms';

import { MatError, MatFormField, MatLabel } from '@angular/material/form-field';
import { MatInput } from '@angular/material/input';
import { MatButton } from '@angular/material/button';
import { MatOption } from '@angular/material/core';
import { MatSelect } from '@angular/material/select';
import { IATSTraeger } from '../_interface/atstraeger';
import { BaseChartDirective } from 'ng2-charts';
import ChartDataLabels from 'chartjs-plugin-datalabels';
import { Chart, ChartData, ChartOptions } from 'chart.js';
import { MatTableDataSource, MatTableModule } from '@angular/material/table';
import { MatPaginator, MatPaginatorModule } from '@angular/material/paginator';
import { MatIconModule } from '@angular/material/icon';
import { MatSort, MatSortModule } from '@angular/material/sort';
import { IStammdaten } from '../_interface/stammdaten';
import { forkJoin } from 'rxjs';
import { DateInputMaskDirective } from '../_directive/date-input-mask.directive';

Chart.register(ChartDataLabels);

@Component({
  selector: 'app-fmd',
  imports: [
    ImrHeaderComponent,
    MatCardModule,
    MatTabsModule,
    FormsModule,
    ReactiveFormsModule,
    MatFormField,
    MatLabel,
    MatSelect,
    MatOption,
    MatButton,
    MatInput,
    MatError,
    MatTableModule,
    BaseChartDirective,
    MatIconModule,
    MatSortModule,
    MatPaginatorModule,
    DateInputMaskDirective,
  ],
  templateUrl: './fmd.component.html',
  styleUrl: './fmd.component.sass'
})

export class FmdComponent implements OnInit, AfterViewInit {
  private apiHttpService = inject(ApiHttpService);
  private authSessionService = inject(AuthSessionService);
  private collectionUtilsService = inject(CollectionUtilsService);
  private navigationService = inject(NavigationService);
  private uiMessageService = inject(UiMessageService);
  router = inject(Router);
  cd = inject(ChangeDetectorRef)

  title = "FMD";
  modul = "fmd";

  mitglieder: IMitglied[] = [];
  mitgliederGesamt: IMitglied[] = [];
  atstraeger: IATSTraeger[] = [];
  currentYear = new Date().getFullYear();
  activeTabIndex = 0;

  private readonly tabsMitTabelle = new Set<number>([1, 2, 3, 4]);
  private readonly sortIndexByTab: Record<number, number> = { 1: 0, 2: 1, 3: 2, 4: 3 };

  get freieMitglieder(): IMitglied[] {
    return this.mitglieder.filter(m =>
      !this.atstraeger.some(a => a.mitglied_id === m.pkid)
    );
  }

  get dropdownMitglieder(): IMitglied[] {
    const frei = this.freieMitglieder;
    const currentId = this.formModul.controls['mitglied_id'].value as number;
    let liste: IMitglied[];

    if (Number(currentId)) {
      const aktuell = this.mitglieder.find(m => m.pkid === Number(currentId));
      if (aktuell && !frei.some(m => m.pkid === Number(currentId))) {
        liste = [aktuell, ...frei];
      } else {
        liste = frei;
      }
    } else {
      liste = frei;
    }

    return this.collectionUtilsService.arraySortByKey(liste, 'stbnr');
  }

  breadcrumb: any = [];

  pageOptions: any[] = [5, 10, 50, 100]

  dataSource = new MatTableDataSource<IATSTraeger>(this.atstraeger);
  sichtbareSpaltenATS: string[] = ['stbnr', 'vorname', 'nachname', 'actions'];
  sichtbareSpaltenUntersuchung: string[] = ['stbnr', 'vorname', 'nachname', 'letzte_untersuchung', 'naechste_untersuchung'];
  sichtbareSpaltenLeistungstest: string[] = ['stbnr', 'vorname', 'nachname', 'leistungstest', 'leistungstest_art'];
  sichtbareSpaltenTauglichkeit: string[] = ['stbnr', 'vorname', 'nachname', 'tauglichkeit'];

  columnsByTab: string[][] = [
    [], // Übersicht
    this.sichtbareSpaltenATS,
    this.sichtbareSpaltenUntersuchung,
    this.sichtbareSpaltenLeistungstest,
    this.sichtbareSpaltenTauglichkeit
  ];

  public pieChartType: 'doughnut' = 'doughnut';
  public pieChartOptions: ChartOptions<'doughnut'> = {
    responsive: true,
    plugins: {
      datalabels: {
        color: '#000',
        font: {
          weight: 'bold',
          size: 14
        },
        formatter: (value, ctx) => {
          return value;
        }
      }
    }
  };

  chartAlter: ChartData<'doughnut', number[], string | string[]> = {
    labels: ['16-18', '19-39', '40-54', '55-65'],
    datasets: [{ data: [0, 0, 0, 0], backgroundColor: ['#69c7a8', '#c973c4', '#d6b36d', '#cfc95d'] }]
  };

  chartTauglichkeit: ChartData<'doughnut', number[], string | string[]> = {
    labels: ['tauglich', 'kein Leistungstest', 'kein Arzt'],
    datasets: [{ data: [0, 0, 0], backgroundColor: ['#32a852', '#fcba56', '#bf6763'] }]
  };

  chartUntersuchung: ChartData<'doughnut', number[], string | string[]> = {
    labels: ['kein Arzt', 'gültig'],
    datasets: [{ data: [0, 0], backgroundColor: ['#bf6763', '#32a852'] }]
  };

  formModul = new FormGroup({
    id: new FormControl(''),
    mitglied_id: new FormControl(0),
    arzt: new FormControl(''),
    arzt_typ: new FormControl(''),
    letzte_untersuchung: new FormControl('', [
      Validators.pattern(/^([0-3]\d)\.([0-1]\d)\.(\d{4})$/),
      this.validDateDDMMYYYY()
    ]),
    leistungstest: new FormControl(''),
    leistungstest_art: new FormControl(''),
    notizen: new FormControl(''),
    fdisk_aenderung: new FormControl('', [
      Validators.pattern(/^([0-3]\d)\.([0-1]\d)\.(\d{4})$/),
      this.validDateDDMMYYYY()
    ]),
  });

  arzttypen: any = [
    "Praktischer Arzt",
    "FW Arzt",
    "Betriebsarzt"
  ]

  leistungstestarten: any = [
    "unbekannt",
    "Finnentest",
    "Fahrrad",
    "Cooper (Laufen)"
  ]

  modul_konfig: any = {};
  pdf_konfig: any = {};
  stammdaten: any = {};

  @ViewChildren(BaseChartDirective) charts?: QueryList<BaseChartDirective>;
  @ViewChild(MatPaginator, { static: false }) paginator?: MatPaginator;
  @ViewChildren(MatSort) sorts?: QueryList<MatSort>;

  ngAfterViewInit() {
    if (this.hasTable(this.activeTabIndex) && this.paginator) {
      this.dataSource.paginator = this.paginator;
    }
    this.setActiveSortForTab(this.activeTabIndex);
    this.updateFilterPredicateFor(this.activeTabIndex);
    this.triggerAllChartsUpdate();
  }

  hasTable(index: number): boolean {
    return this.tabsMitTabelle.has(index);
  }

  ngOnInit(): void {
    sessionStorage.setItem("PageNumber", "2");
    sessionStorage.setItem("Page2", "FMD");
    this.breadcrumb = this.navigationService.ladeBreadcrumb();
    this.formModul.disable();

    forkJoin({
      main: this.apiHttpService.get<any[]>(this.modul),
      context: this.apiHttpService.get<any>(`${this.modul}/context`),
    }).subscribe({
      next: ({ main, context }) => {
        try {
          const konfigs = context.modul_konfig.find((m: any) => m.modul === 'fmd');
          this.modul_konfig = konfigs?.konfiguration ?? [];
          
          const templates = context.modul_konfig.find((m: any) => m.modul === 'pdf');
          this.pdf_konfig = templates?.konfiguration ?? [];

          this.stammdaten = <IStammdaten>context.konfig[0];

          const mains = main as any[];
          this.mitglieder = context.mitglieder as any[];
          this.mitgliederGesamt = context.mitglieder as any[];
          const memberMap = new Map<number, any>(this.mitglieder.map((m: any) => [m.pkid, m]));

          this.atstraeger = mains.map(item => {
            const mitg = memberMap.get(item.mitglied_id) || {};
            return {
              ...item,
              stbnr: mitg.stbnr,
              vorname: mitg.vorname,
              nachname: mitg.nachname,
              geburtsdatum: mitg.geburtsdatum,
              hauptberuflich: mitg.hauptberuflich
            };
          });

          this.mitglieder = this.mitglieder.filter((m: any) => m.hauptberuflich == false);

          this.mitglieder = this.collectionUtilsService.arraySortByKey(this.mitglieder, 'stbnr');
          this.atstraeger = this.collectionUtilsService.arraySortByKey(this.atstraeger, 'stbnr');
          this.dataSource.data = this.atstraeger;
          this.updateTauglichkeitFürAlle();
          this.updateChartData();
        } catch (e: any) {
          this.uiMessageService.erstelleMessage("error", e);
        }
      },
      error: (error: any) => {
        this.authSessionService.errorAnzeigen(error);
      }
    });
  }

  applyFilter(value: string): void {
    this.dataSource.filter = (value || '').trim().toLowerCase();
    this.paginator?.firstPage();
  }

  neueDetails(): void {
    this.formModul.enable();
  }

  auswahlBearbeiten(element: any): void {
    if (element.id === 0) {
      return;
    }
    const abfrageUrl = `${this.modul}/${element.id}`;

    this.apiHttpService.get(abfrageUrl).subscribe({
      next: (erg: any) => {
        try {
          const details: IATSTraeger = erg;

          this.formModul.enable();
          this.formModul.setValue({
            id: details.id,
            mitglied_id: details.mitglied_id,
            arzt: details.arzt,
            arzt_typ: details.arzt_typ,
            letzte_untersuchung: details.letzte_untersuchung,
            leistungstest: details.leistungstest,
            leistungstest_art: details.leistungstest_art,
            notizen: details.notizen,
            fdisk_aenderung: details.fdisk_aenderung
          });
        } catch (e: any) {
          this.uiMessageService.erstelleMessage('error', e);
        }
      },
      error: (error: any) => {
        this.authSessionService.errorAnzeigen(error);
      }
    });
  }

  datenSpeichern(): void {
    if (this.formModul.invalid) {
      this.uiMessageService.erstelleMessage('error', 'Bitte alle Pflichtfelder korrekt ausfüllen!');
      return;
    }

    const objekt: any = this.formModul.value;
    const idValue = this.formModul.controls['id'].value;

    const mitglied = this.mitglieder.find(m => m.pkid === objekt.mitglied_id);
    const gebDatum = mitglied?.geburtsdatum ?? null;
    const alter = this.berechneAlter(gebDatum);

    if (objekt.letzte_untersuchung != '' && objekt.letzte_untersuchung != null) {
      const parts = objekt.letzte_untersuchung.split('.');
      if (parts.length === 3) {
        const [tag, monat, jahr] = parts.map((n: any) => parseInt(n, 10));
        if (!isNaN(tag) && !isNaN(monat) && !isNaN(jahr)) {
          const datum = new Date(jahr, monat - 1, tag);

          const match = this.modul_konfig.intervall
            .find((i: any) => alter >= i.von && alter <= i.bis);

          if (match) {
            const nextYear = datum.getFullYear() + match.intervall;
            objekt.naechste_untersuchung = nextYear.toString();
          } else {
            objekt.naechste_untersuchung = '';
          }
        }
      }
    } else {
      objekt.naechste_untersuchung = '';
    }

    const currentYear = new Date().getFullYear();
    let testJahr: number | null = null;
    if (objekt.leistungstest) {
      const partsLS = objekt.leistungstest.split('.');
      if (partsLS.length === 3) {
        const [, , jahrLS] = partsLS.map((n: any) => parseInt(n, 10));
        if (!isNaN(jahrLS)) testJahr = jahrLS;
      }
    }

    const nextYearNum = Number(objekt.naechste_untersuchung);

    if (
      objekt.letzte_untersuchung !== '' &&
      objekt.leistungstest !== '' &&
      !isNaN(nextYearNum) &&
      nextYearNum > currentYear &&
      testJahr !== null &&
      testJahr >= currentYear - 1
    ) {
      objekt.tauglichkeit = 'tauglich';
    } else {
      objekt.tauglichkeit = 'nein';
    }


    if (!idValue) {
      this.apiHttpService.post(this.modul, objekt, false).subscribe({
        next: (erg: any) => {
          try {
            const newTraeger: any = erg;
            const mitg = this.mitglieder.find(m => m.pkid === newTraeger.mitglied_id);

            if (mitg) {
              newTraeger.stbnr = mitg.stbnr;
              newTraeger.vorname = mitg.vorname;
              newTraeger.nachname = mitg.nachname;
              newTraeger.hauptberuflich = mitg.hauptberuflich;
            }

            this.atstraeger.push(newTraeger);
            this.atstraeger = this.collectionUtilsService.arraySortByKey(this.atstraeger, 'stbnr');
            this.dataSource.data = this.atstraeger;
            this.updateChartData();

            this.formModul.reset({
              id: '',
              mitglied_id: 0,
              arzt: '',
              arzt_typ: '',
              letzte_untersuchung: '',
              leistungstest: '',
              leistungstest_art: '',
              notizen: '',
              fdisk_aenderung: ''
            });
            this.formModul.disable();
            this.uiMessageService.erstelleMessage('success', 'ATS Träger gespeichert!');
          } catch (e: any) {
            this.uiMessageService.erstelleMessage('error', e);
          }
        },
        error: (error: any) => this.authSessionService.errorAnzeigen(error)
      });
    } else {
      this.apiHttpService.patch(this.modul, idValue, objekt, false).subscribe({
        next: (erg: any) => {
          try {
            const updated: any = erg;
            const mitg = this.mitglieder.find(m => m.pkid === updated.mitglied_id);
            if (mitg) {
              updated.stbnr = mitg.stbnr;
              updated.vorname = mitg.vorname;
              updated.nachname = mitg.nachname;
              updated.hauptberuflich = mitg.hauptberuflich;
            }
            this.atstraeger = this.atstraeger
              .map(m => m.id === updated.id ? updated : m)
              .sort((a, b) => a.stbnr - b.stbnr);

            this.dataSource.data = this.atstraeger;

            this.formModul.reset({
              id: '',
              mitglied_id: 0,
              arzt: '',
              arzt_typ: '',
              letzte_untersuchung: '',
              leistungstest: '',
              leistungstest_art: '',
              notizen: '',
              fdisk_aenderung: ''
            });
            this.formModul.disable();
            this.updateChartData();

            this.uiMessageService.erstelleMessage('success', 'ATS Träger geändert!');
          } catch (e: any) {
            this.uiMessageService.erstelleMessage('error', e);
          }
        },
        error: (error: any) => this.authSessionService.errorAnzeigen(error)
      });
    }
  }

  abbrechen(): void {
    this.uiMessageService.erstelleMessage("info", "ATS Träger nicht gespeichert!");
    this.formModul.reset({
      id: '',
      mitglied_id: 0,
      arzt: '',
      arzt_typ: '',
      letzte_untersuchung: '',
      leistungstest: '',
      leistungstest_art: '',
      notizen: '',
      fdisk_aenderung: ''
    });
    this.formModul.disable();
  }

  datenLoeschen(): void {
    const id = this.formModul.controls['id'].value!;
    if (!id) {
      this.uiMessageService.erstelleMessage('error', 'Kein ATS Träger ausgewählt zum Löschen!');
      return;
    }

    this.apiHttpService.delete(this.modul, id).subscribe({
      next: (erg: any) => {
        try {
          this.atstraeger = this.atstraeger.filter((m: any) => m.id !== id);
          this.dataSource.data = this.atstraeger;
          this.updateChartData();

          this.formModul.reset({
            id: '',
            mitglied_id: 0,
            arzt: '',
            arzt_typ: '',
            letzte_untersuchung: '',
            leistungstest: '',
            leistungstest_art: '',
            notizen: '',
            fdisk_aenderung: ''
          });
          this.formModul.disable();

          this.uiMessageService.erstelleMessage('success', 'ATS Träger erfolgreich gelöscht!');
        } catch (e: any) {
          this.uiMessageService.erstelleMessage('error', e);
        }
      },
      error: (error: any) => {
        this.authSessionService.errorAnzeigen(error);
      }
    });
  }

  validDateDDMMYYYY(): ValidatorFn {
    return (control: AbstractControl) => {
      const v: string = control.value;
      if (!v || !/^([0-3]\d)\.([0-1]\d)\.(\d{4})$/.test(v)) {
        return null;
      }
      const [t, m, j] = v.split('.').map(x => +x);
      const d = new Date(j, m - 1, t);
      return (d.getFullYear() === j && d.getMonth() === m - 1 && d.getDate() === t)
        ? null
        : { dateInvalid: true };
    };
  }

  berechneAlter(geburtsdatum?: string | Date | null): number {
    if (!geburtsdatum) {
      return 0;
    }

    let geb: Date;
    if (typeof geburtsdatum === 'string') {
      const parts = geburtsdatum.split('.');
      if (parts.length !== 3) {
        return 0;
      }
      const [t, m, j] = parts.map(n => parseInt(n, 10));
      geb = new Date(j, m - 1, t);
      if (isNaN(geb.getTime())) {
        return 0;
      }
    } else {
      geb = geburtsdatum;
    }
    const today = new Date();
    let age = today.getFullYear() - geb.getFullYear();
    const monDiff = today.getMonth() - geb.getMonth();
    const dayDiff = today.getDate() - geb.getDate();
    if (monDiff < 0 || (monDiff === 0 && dayDiff < 0)) {
      age--;
    }
    return age;
  }

  updateTauglichkeitFürAlle(): void {
    const currentYear = new Date().getFullYear();
    
    this.atstraeger.forEach(item => {
      const lastYear = this.getYearFromDate(item.letzte_untersuchung);
      const testYear = this.getYearFromDate(item.leistungstest);
      const nextYear = item.naechste_untersuchung
        ? parseInt(item.naechste_untersuchung, 10)
        : NaN;

      if (
        !isNaN(lastYear) &&
        !isNaN(testYear) &&
        !isNaN(nextYear) &&
        lastYear > 0 &&
        Boolean(item.leistungstest) &&
        testYear >= currentYear - 1 &&
        nextYear > currentYear
      ) {
        item.tauglichkeit = 'tauglich';
      } else {
        item.tauglichkeit = 'nein';
      }
    });
  }

  isOlderThanLastYear(dateInput?: string | Date | null): boolean {
    const year = this.getYearFromDate(dateInput);
    if (isNaN(year)) return false;
    const currentYear = new Date().getFullYear();
    return year < currentYear - 1;
  }

  getYearFromDate(dateStr?: string | Date | null): number {
    if (!dateStr) return NaN;

    if (dateStr instanceof Date) return dateStr.getFullYear();

    const s = String(dateStr).trim();

    // dd.mm.yyyy
    const parts = s.split('.');
    if (parts.length === 3) return parseInt(parts[2], 10);

    // ISO yyyy-mm-dd...
    const m = s.match(/^(\d{4})-/);
    if (m) return parseInt(m[1], 10);

    return NaN;
  }

  updateChartData(): void {
    this.updateAlterChart();
    this.updateTauglichkeitChart();
    this.updateUntersuchungChart();
  }

  private triggerAllChartsUpdate() {
    this.cd.detectChanges();
    queueMicrotask(() => this.charts?.forEach(c => c.update()));
  }

  private setActiveSortForTab(tabIndex: number): void {
    const sortIdx = this.sortIndexByTab[tabIndex];
    const activeSort = sortIdx !== undefined ? this.sorts?.get(sortIdx) : undefined;
    this.dataSource.sort = (activeSort as MatSort | undefined) ?? (undefined as any);
  }

  updateAlterChart(): void {
    const zaehler = [0, 0, 0, 0];

    this.atstraeger.forEach(traeger => {
      const alter = this.berechneAlter(traeger.geburtsdatum);
      if (alter >= 16 && alter <= 18) zaehler[0]++;
      else if (alter >= 19 && alter <= 39) zaehler[1]++;
      else if (alter >= 40 && alter <= 54) zaehler[2]++;
      else if (alter >= 55 && alter <= 65) zaehler[3]++;
    });

    this.chartAlter.datasets[0].data = zaehler;
    this.triggerAllChartsUpdate();
  }

  updateTauglichkeitChart(): void {
    const zaehler = [0, 0, 0];
    const currentYear = new Date().getFullYear();

    this.atstraeger.forEach(traeger => {
      const testStr = traeger.leistungstest;
      const hasTest = testStr != null && String(testStr).trim() !== '' && testStr !== 'nein';

      const nextStr = traeger.naechste_untersuchung;
      const hasNext = nextStr != null && String(nextStr).trim() !== '';
      const nextYear = hasNext ? Number(nextStr) : NaN;

      if (traeger.tauglichkeit === 'tauglich') {
        zaehler[0]++;
        return;
      }

      // "kein Arzt" / Untersuchung nicht gültig
      if (!hasNext || isNaN(nextYear) || nextYear <= currentYear) {
        zaehler[2]++;
        return;
      }

      // "kein Leistungstest" (fehlt oder zu alt)
      if (!hasTest || this.isOlderThanLastYear(testStr)) {
        zaehler[1]++;
        return;
      }

      // Fallback: wenn was durchrutscht, zählt es sinnvollerweise als "kein Leistungstest"
      zaehler[1]++;
    });

    this.chartTauglichkeit.datasets[0].data = zaehler;
    this.triggerAllChartsUpdate();
  }

  updateUntersuchungChart(): void {
    const zaehler = [0, 0];
    const currentYear = new Date().getFullYear();

    this.atstraeger.forEach(traeger => {
      const nextStr = traeger.naechste_untersuchung;
      const hasNext = nextStr != null && String(nextStr).trim() !== '';
      const nextYear = hasNext ? Number(nextStr) : NaN;

      if (!hasNext || isNaN(nextYear) || nextYear <= currentYear) {
        zaehler[0]++; // kein Arzt / ungültig / überfällig
      } else {
        zaehler[1]++; // gültig
      }
    });

    this.chartUntersuchung.datasets[0].data = zaehler;
    this.triggerAllChartsUpdate();
  }

  private updateFilterPredicateFor(tabIndex: number) {
    const cols = this.columnsByTab[tabIndex] ?? [];
    if (!cols.length) {
      // Übersicht: alles durchlassen (oder leer)
      this.dataSource.filterPredicate = () => true;
      return;
    }
    this.dataSource.filterPredicate = (row: any, filter: string) => {
      const haystack = cols.map(c => String(row?.[c] ?? '').toLowerCase()).join(' ');
      return haystack.includes(filter);
    };
  }

  onTabChange(index: number): void {
    this.activeTabIndex = index;

    this.cd.detectChanges();
    queueMicrotask(() => {
      if (this.hasTable(index)) {
        if (this.paginator) {
          this.dataSource.paginator = this.paginator;
          this.paginator.firstPage();
        }
        this.setActiveSortForTab(index);
        this.updateFilterPredicateFor(index);
        this.dataSource.filter = this.dataSource.filter;
      } else {
        this.dataSource.paginator = undefined as any;
        this.dataSource.sort = undefined as any;
      }
    });
  }

  isLeistungstestOk(value: any): boolean {
    if (value == null) return false;
    const s = String(value).trim().toLowerCase();
    if (!s || s === 'nein') return false;

    const year = this.getYearFromDate(value);
    if (isNaN(year)) return false;

    const currentYear = new Date().getFullYear();
    return year >= currentYear - 1; // aktuelles oder letztes Jahr
  }

  printChecklist(element: any): void {
    if (!element?.id) return;
    const idPdfCheckliste = this.pdf_konfig['idFmdDeckblatt'];
    const abfrageUrl = `pdf/templates/${idPdfCheckliste}/render`;

    let heute: any = new Date().toLocaleString('de-DE');
    heute = heute.split(",");
    heute = heute[0];

    const payload = {
      "druck_datum": heute,
      "fw_name": this.stammdaten.fw_name,
      "fw_nummer": this.stammdaten.fw_nummer,
      "fw_street": this.stammdaten.fw_street,
      "fw_plz": this.stammdaten.fw_plz,
      "fw_ort": this.stammdaten.fw_ort,
      "fw_email": this.stammdaten.fw_email,
      "fw_telefon": this.stammdaten.fw_telefon,
      "mitglied_stbnr": element.stbnr ?? "",
      "mitglied_vorname": element.vorname ?? "",
      "mitglied_zuname": element.nachname ?? "",
      "mitglied_alter": this.berechneAlter(element.geburtsdatum) ?? 0,
      "mitglied_letzte_untersuchung": element.letzte_untersuchung ?? ""
    }

    this.apiHttpService.postBlob(abfrageUrl, payload).subscribe({
      next: (blob: Blob) => {
        if (blob.size === 0) {
          this.uiMessageService.erstelleMessage('error', 'PDF ist leer (0 Bytes).');
          return;
        }

        const url = URL.createObjectURL(blob);
        window.open(url, '_blank');
      },
      error: (error: any) => this.authSessionService.errorAnzeigen(error)
    });
  }

  printOffeneUntersuchugen(): void {
    const today = new Date();
    let data = this.atstraeger.filter((m: any) => m.naechste_untersuchung == null || Number(m.naechste_untersuchung) <= today.getFullYear());
    data = this.collectionUtilsService.arraySortByKey(data, 'naechste_untersuchung');
    this.printListe(data, "untersuchungen");
  }

  printTauglichkeit(): void {
    this.printListe(this.atstraeger, "tauglichkeit");
  }

  printLeistungstest(): void {
    this.printListe(this.atstraeger, "leistungstest");
  }

  private getYearSafe(value: any): number | null {
    if (value == null) return null;

    // falls du schon Jahreszahlen als "2027" bekommst
    if (typeof value === "number" && Number.isFinite(value)) return value;

    if (typeof value === "string") {
      const v = value.trim().toLowerCase();
      if (!v || v === "nein" || v === "none" || v === "null") return null;

      // "2027" direkt als Jahr
      const asNum = Number(v);
      if (Number.isFinite(asNum) && asNum > 1900 && asNum < 3000) return asNum;
    }

    const d = new Date(value);
    if (Number.isNaN(d.getTime())) return null;
    return d.getFullYear();
  }

  printAlleMitglieder(): void {
    const memberMap = new Map<number, any>(
      this.atstraeger.map((a: any) => [Number(a.mitglied_id), a])
    );

    const toBool = (v: any): boolean =>
      v === true || v === 1 || v === "1" ||
      (typeof v === "string" && v.trim().toLowerCase() === "true");

    const data = this.mitgliederGesamt.map((m: any) => {
      const ats = memberMap.get(Number(m.pkid));

      // BF primär aus Mitglied, sonst aus ATS
      const isBF = toBool(m.hauptberuflich) || (ats ? toBool(ats.hauptberuflich) : false);

      // ATS-Träger: wenn ATS-Datensatz vorhanden -> Ja, sonst Nein
      // (Wenn du einen eigenen Mitglied-Flag hast, hier ergänzen: || toBool(m.ist_ats_traeger))
      const istAtsTraeger = !!ats;
      const liste_ats = istAtsTraeger ? "Ja" : "Nein";

      // ATS Felder (leer wenn nicht vorhanden)
      const tauglichkeit = ats?.tauglichkeit ?? null;
      const naechste_untersuchung = ats?.naechste_untersuchung ?? null;
      const leistungstest = ats?.leistungstest ?? null;

      const liste_tauglich =
        tauglichkeit == null ? "" : (tauglichkeit === "tauglich" ? "Ja" : "Nein");

      // Arzt: Status + Jahr (wenn vorhanden)
      const arztJahr = this.getYearSafe(naechste_untersuchung);
      let liste_arzt = "";
      if (arztJahr != null) {
        liste_arzt = arztJahr <= this.currentYear ? `Nicht OK | ${arztJahr}` : `OK | ${arztJahr}`;
      } else {
        // keine Info -> leer lassen (so wolltest du es)
        liste_arzt = "";
      }

      // Leistungstest (wie gehabt, nur Jahr safe)
      const hasNoTest =
        typeof leistungstest === "string" && leistungstest.trim().toLowerCase() === "nein";
      const testJahr = this.getYearSafe(leistungstest);

      let liste_leistungstest = "";
      if (leistungstest == null) {
        liste_leistungstest = "";
      } else if (hasNoTest) {
        liste_leistungstest = "Nicht OK";
      } else if (this.isLeistungstestOk(leistungstest)) {
        liste_leistungstest = "OK";
      } else {
        liste_leistungstest = `Nicht OK${testJahr ? " | " + testJahr : ""}`;
      }

      // BF überschreibt Anzeige (egal ob ATS vorhanden)
      if (isBF) {
        return {
          ...m,
          tauglichkeit,
          naechste_untersuchung,
          leistungstest,
          liste_ats: "Ja",
          liste_tauglich: "Ja",
          liste_arzt: "BF",
          liste_leistungstest: "BF",
        };
      }

      if (liste_ats == "Nein") {
        return {
          ...m,
          tauglichkeit,
          naechste_untersuchung,
          leistungstest,
          liste_ats,
          liste_tauglich: "-",
          liste_arzt: "-",
          liste_leistungstest: "-",
        };
      }

      return {
        ...m,
        tauglichkeit,
        naechste_untersuchung,
        leistungstest,
        liste_ats,
        liste_tauglich,
        liste_arzt,
        liste_leistungstest,
      };
    });

    const data_sort = this.collectionUtilsService.arraySortByKey(data, "nachname");

    this.printListe(data_sort, "gesamt");
  }

  printListe(data: any, typ: string): void {
    const idPdfListe = this.pdf_konfig['idFmdListe'];
    const abfrageUrl = `pdf/templates/${idPdfListe}/render`;

    let heute: any = new Date().toLocaleString('de-DE');
    heute = heute.split(",");
    heute = heute[0];

    const payload = {
      "druck_datum": heute,
      "fw_name": this.stammdaten.fw_name,
      "fw_nummer": this.stammdaten.fw_nummer,
      "fw_street": this.stammdaten.fw_street,
      "fw_plz": this.stammdaten.fw_plz,
      "fw_ort": this.stammdaten.fw_ort,
      "fw_email": this.stammdaten.fw_email,
      "fw_telefon": this.stammdaten.fw_telefon,
      "ats_traeger_liste": data,
      "fmd_export_liste_typ": typ
    }

    this.apiHttpService.postBlob(abfrageUrl, payload).subscribe({
      next: (blob: Blob) => {
        if (blob.size === 0) {
          this.uiMessageService.erstelleMessage('error', 'PDF ist leer (0 Bytes).');
          return;
        }

        const url = URL.createObjectURL(blob);
        window.open(url, '_blank');
      },
      error: (error: any) => this.authSessionService.errorAnzeigen(error)
    });

  }
}

import { Component, OnDestroy, OnInit, inject } from '@angular/core';
import { A11yModule } from '@angular/cdk/a11y';
import { FormControl, FormsModule, ReactiveFormsModule } from '@angular/forms';
import { MatAutocompleteModule, MatAutocompleteSelectedEvent } from '@angular/material/autocomplete';
import { MatButton } from '@angular/material/button';
import { MatOption } from '@angular/material/core';
import { MatFormField, MatLabel } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { Observable, forkJoin, map, of } from 'rxjs';

import {
  ImrHeaderComponent,
  ImrPageLayoutComponent,
  ImrSectionCardComponent,
  ImrTopActionsComponent,
} from '../imr-ui-library';
import { IMitglied } from '../_interface/mitglied';
import { IHomepageDienstposten } from '../_interface/homepage';
import { ApiHttpService } from '../_service/api-http.service';
import { AuthSessionService } from '../_service/auth-session.service';
import { CollectionUtilsService } from '../_service/collection-utils.service';
import { NavigationService } from '../_service/navigation.service';
import { UiMessageService } from '../_service/ui-message.service';
interface HomepageSectionTemplate {
  id: string;
  title: string;
  positions: string[];
}

interface HomepageRowDraft extends IHomepageDienstposten {
  local_id: string;
  mitglied_id: number | null;
}

interface HomepageSectionDraft {
  local_id: string;
  id: string;
  title: string;
  order: number;
  members: HomepageRowDraft[];
}

interface PendingPhotoOperation {
  row_key: string;
  file?: File;
  remove_photo?: boolean;
}

const DEFAULT_PLAN_TEMPLATE: ReadonlyArray<HomepageSectionTemplate> = [
  {
    id: 'kommando',
    title: 'Kommando',
    positions: ['Kommandant', 'Kommandant Stv.', 'Leiter des Verwaltungsdienstes'],
  },
  {
    id: 'zugskommandanten',
    title: 'Zugskommandanten',
    positions: ['Zugskommandant', 'Zugskommandant'],
  },
  {
    id: 'gruppenkommandanten',
    title: 'Gruppenkommandanten',
    positions: [
      'Gruppenkommandant',
      'Gruppenkommandant',
      'Gruppenkommandant',
      'Gruppenkommandant',
      'Gruppenkommandant',
    ],
  },
  {
    id: 'sachbearbeiter',
    title: 'Sachbearbeiter',
    positions: [
      'Fahrmeister',
      'Zeugmeister',
      'Ausbilder',
      'Jugendbetreuer',
      'Feuerwehrkurat',
      'SB Nachrichtendienst',
      'SB Schadstoff',
      'SB Feuerwehr Medizinischer Dienst (FMD)',
      'SB Vorbeugender Brandschutz',
      'SB Oeffentlichkeitsarbeit',
      'SB EDV',
      'SB Atemschutz',
    ],
  },
];

@Component({
  selector: 'app-homepage',
  imports: [
    A11yModule,
    ImrHeaderComponent,
    ImrPageLayoutComponent,
    ImrSectionCardComponent,
    ImrTopActionsComponent,
    FormsModule,
    ReactiveFormsModule,
    MatFormField,
    MatLabel,
    MatInputModule,
    MatAutocompleteModule,
    MatOption,
    MatButton,
  ],
  templateUrl: './homepage.component.html',
  styleUrl: './homepage.component.sass',
})
export class HomepageComponent implements OnInit, OnDestroy {
  private apiHttpService = inject(ApiHttpService);
  private authSessionService = inject(AuthSessionService);
  private collectionUtilsService = inject(CollectionUtilsService);
  private navigationService = inject(NavigationService);
  private uiMessageService = inject(UiMessageService);

  title = 'Homepage Dienstpostenplan';
  modul = 'homepage/intern';
  modulBulk = 'homepage/intern/bulk';
  modulContext = 'homepage/context';

  breadcrumb: any[] = [];
  loading = false;

  sections: HomepageSectionDraft[] = [];
  mitglieder: IMitglied[] = [];
  photoModalOpen = false;
  photoModalUrl: string | null = null;

  private sectionCounter = 0;
  private rowCounter = 0;
  private mitgliederByPkid = new Map<number, IMitglied>();
  private mitgliedControls = new Map<string, FormControl<string>>();
  private pendingPhotoUploads = new Map<string, File>();
  private pendingPhotoRemovals = new Set<string>();
  private pendingPhotoPreviewUrls = new Map<string, string>();
  private focusBeforePhotoModal: HTMLElement | null = null;

  ngOnInit(): void {
    sessionStorage.setItem('PageNumber', '2');
    sessionStorage.setItem('Page2', 'HOME');
    this.breadcrumb = this.navigationService.ladeBreadcrumb();
    this.ladeDaten();
  }

  ngOnDestroy(): void {
    this.closePhotoPreview();
    this.clearAllPendingPhotoPreviewUrls();
  }

  private ladeDaten(): void {
    this.loading = true;

    forkJoin({
      rows: this.apiHttpService.get<IHomepageDienstposten[]>(this.modul),
      context: this.apiHttpService.get<{ mitglieder: IMitglied[] }>(this.modulContext),
    }).subscribe({
      next: ({ rows, context }) => {
        try {
          const contextMitglieder = (context?.mitglieder ?? []) as IMitglied[];
          this.mitglieder = this.collectionUtilsService.arraySortByKey(contextMitglieder, 'stbnr') as IMitglied[];
          this.mitgliederByPkid = new Map(this.mitglieder.map((mitglied) => [mitglied.pkid, mitglied]));

          this.sections = this.mapRowsToSections(Array.isArray(rows) ? rows : []);
          this.mitgliedControls.clear();
          this.clearAllPendingPhotoPreviewUrls();
          this.pendingPhotoUploads.clear();
          this.pendingPhotoRemovals.clear();
          this.closePhotoPreview();
          this.normalizeSectionsInPlace();
        } catch (e: any) {
          this.uiMessageService.erstelleMessage('error', String(e));
        } finally {
          this.loading = false;
        }
      },
      error: (error: any) => {
        this.loading = false;
        this.authSessionService.errorAnzeigen(error);
      },
    });
  }

  private mapRowsToSections(rows: IHomepageDienstposten[]): HomepageSectionDraft[] {
    if (rows.length === 0) {
      return this.createDefaultSections();
    }

    const orderedRows = [...rows].sort((a, b) => {
      const sectionOrderDiff = Number(a.section_order ?? 0) - Number(b.section_order ?? 0);
      if (sectionOrderDiff !== 0) {
        return sectionOrderDiff;
      }

      const rowOrderDiff = Number(a.position_order ?? 0) - Number(b.position_order ?? 0);
      if (rowOrderDiff !== 0) {
        return rowOrderDiff;
      }

      return String(a.position ?? '').localeCompare(String(b.position ?? ''), 'de');
    });

    const grouped = new Map<string, HomepageSectionDraft>();

    for (const row of orderedRows) {
      const sectionId = this.normalizeSectionId(row.section_id || row.section_title || 'sektion');
      const sectionTitle = (row.section_title || sectionId || 'Sektion').trim();
      const sectionOrder = Number(row.section_order ?? grouped.size + 1);

      let section = grouped.get(sectionId);
      if (!section) {
        section = {
          local_id: this.createSectionLocalId(),
          id: sectionId,
          title: sectionTitle,
          order: sectionOrder,
          members: [],
        };
        grouped.set(sectionId, section);
      }

      section.members.push(
        this.createRowDraft(
          section,
          row.position || `Position ${section.members.length + 1}`,
          Number(row.position_order ?? section.members.length + 1),
          row,
        ),
      );
    }

    return Array.from(grouped.values()).sort((a, b) => a.order - b.order);
  }

  private createDefaultSections(): HomepageSectionDraft[] {
    return DEFAULT_PLAN_TEMPLATE.map((template, sectionIndex) => {
      const section: HomepageSectionDraft = {
        local_id: this.createSectionLocalId(),
        id: template.id,
        title: template.title,
        order: sectionIndex + 1,
        members: [],
      };

      section.members = template.positions.map((position, rowIndex) =>
        this.createRowDraft(section, position, rowIndex + 1),
      );

      return section;
    });
  }

  private createRowDraft(
    section: HomepageSectionDraft,
    position: string,
    positionOrder: number,
    source?: Partial<IHomepageDienstposten>,
  ): HomepageRowDraft {
    return {
      id: source?.id,
      pkid: source?.pkid,
      local_id: this.createRowLocalId(),
      section_id: this.normalizeSectionId(source?.section_id || section.id),
      section_title: (source?.section_title || section.title || 'Sektion').trim(),
      section_order: Number(source?.section_order ?? section.order),
      position: (source?.position || position || '').trim(),
      position_order: Number(source?.position_order ?? positionOrder),
      mitglied_id: source?.mitglied_id ?? null,
      mitglied_name: source?.mitglied_name ?? null,
      fallback_name: (source?.fallback_name || 'Nicht definiert').trim() || 'Nicht definiert',
      fallback_dienstgrad: (source?.fallback_dienstgrad || '').trim(),
      fallback_photo: (source?.fallback_photo || 'X').trim() || 'X',
      fallback_dienstgrad_img:
        (source?.fallback_dienstgrad_img || this.resolveDienstgradImage(source?.fallback_dienstgrad || '')).trim(),
      photo_url: source?.photo_url || null,
      created_at: source?.created_at,
      updated_at: source?.updated_at,
    };
  }

  private createSectionLocalId(): string {
    this.sectionCounter += 1;
    return `section-${this.sectionCounter}`;
  }

  private createRowLocalId(): string {
    this.rowCounter += 1;
    return `row-${this.rowCounter}`;
  }

  private normalizeSectionId(value: string): string {
    const normalized = String(value || '')
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+|-+$/g, '');

    return normalized || 'sektion';
  }

  private makeUniqueSectionId(baseId: string): string {
    const existing = new Set(this.sections.map((section) => section.id));
    if (!existing.has(baseId)) {
      return baseId;
    }

    let counter = 2;
    let candidate = `${baseId}-${counter}`;
    while (existing.has(candidate)) {
      counter += 1;
      candidate = `${baseId}-${counter}`;
    }
    return candidate;
  }

  addSection(): void {
    const order = this.sections.length + 1;
    const baseId = this.normalizeSectionId(`sektion-${order}`);
    const section: HomepageSectionDraft = {
      local_id: this.createSectionLocalId(),
      id: this.makeUniqueSectionId(baseId),
      title: `Neue Sektion ${order}`,
      order,
      members: [],
    };
    section.members.push(this.createRowDraft(section, 'Neue Position', 1));

    this.sections = [...this.sections, section];
    this.normalizeSectionsInPlace();
  }

  removeSection(section: HomepageSectionDraft): void {
    const confirmDelete = window.confirm(`Sektion "${section.title}" wirklich entfernen?`);
    if (!confirmDelete) {
      return;
    }

    section.members.forEach((member) => {
      this.mitgliedControls.delete(member.local_id);
      this.clearPendingPhotoState(member);
    });
    this.sections = this.sections.filter((item) => item.local_id !== section.local_id);

    this.normalizeSectionsInPlace();
  }

  addPosition(section: HomepageSectionDraft): void {
    const positionOrder = section.members.length + 1;
    section.members.push(this.createRowDraft(section, `Neue Position ${positionOrder}`, positionOrder));

    this.normalizeSectionsInPlace();
  }

  removePosition(section: HomepageSectionDraft, row: HomepageRowDraft): void {
    const confirmDelete = window.confirm(`Position "${row.position}" wirklich entfernen?`);
    if (!confirmDelete) {
      return;
    }

    section.members = section.members.filter((entry) => entry.local_id !== row.local_id);
    this.mitgliedControls.delete(row.local_id);
    this.clearPendingPhotoState(row);

    if (section.members.length === 0) {
      section.members.push(this.createRowDraft(section, 'Neue Position', 1));
    }

    this.normalizeSectionsInPlace();
  }

  onSectionMetaChanged(section: HomepageSectionDraft): void {
    section.id = this.normalizeSectionId(section.id || section.title || 'sektion');
    section.title = (section.title || 'Sektion').trim() || 'Sektion';

    this.normalizeSectionsInPlace();
  }

  onRowChanged(section: HomepageSectionDraft, row: HomepageRowDraft, rowIndex: number): void {
    row.position_order = rowIndex + 1;
    row.position = (row.position || '').trim();
    row.section_id = section.id;
    row.section_title = section.title;
    row.section_order = section.order;

  }

  private normalizeSectionsInPlace(): void {
    const usedSectionIds = new Set<string>();

    this.sections = this.sections.map((section, sectionIndex) => {
      let normalizedSectionId = this.normalizeSectionId(section.id || section.title || `sektion-${sectionIndex + 1}`);
      if (usedSectionIds.has(normalizedSectionId)) {
        let suffix = 2;
        while (usedSectionIds.has(`${normalizedSectionId}-${suffix}`)) {
          suffix += 1;
        }
        normalizedSectionId = `${normalizedSectionId}-${suffix}`;
      }
      usedSectionIds.add(normalizedSectionId);

      const normalizedSection: HomepageSectionDraft = {
        ...section,
        order: sectionIndex + 1,
        id: normalizedSectionId,
        title: (section.title || `Sektion ${sectionIndex + 1}`).trim() || `Sektion ${sectionIndex + 1}`,
        members: section.members.map((member, memberIndex) => ({
          ...member,
          section_id: normalizedSectionId,
          section_title: (section.title || `Sektion ${sectionIndex + 1}`).trim() || `Sektion ${sectionIndex + 1}`,
          section_order: sectionIndex + 1,
          position_order: memberIndex + 1,
          position: (member.position || `Position ${memberIndex + 1}`).trim(),
          fallback_name: (member.fallback_name || 'Nicht definiert').trim() || 'Nicht definiert',
          fallback_dienstgrad: (member.fallback_dienstgrad || '').trim(),
          fallback_photo: (member.fallback_photo || 'X').trim() || 'X',
          fallback_dienstgrad_img:
            (member.fallback_dienstgrad_img || this.resolveDienstgradImage(member.fallback_dienstgrad || '')).trim(),
        })),
      };

      return normalizedSection;
    });
  }

  getMitgliedControl(row: HomepageRowDraft): FormControl<string> {
    const existing = this.mitgliedControls.get(row.local_id);
    if (existing) {
      return existing;
    }

    const initialValue = this.resolveMitgliedAutocompleteText(row);
    const created = new FormControl<string>(initialValue, { nonNullable: true });
    this.mitgliedControls.set(row.local_id, created);
    return created;
  }

  private resolveMitgliedAutocompleteText(row: HomepageRowDraft): string {
    if (!row.mitglied_id) {
      return '';
    }

    const mitglied = this.mitgliederByPkid.get(row.mitglied_id);
    return mitglied ? this.getMitgliedLabel(mitglied) : '';
  }

  getFilteredMitglieder(row: HomepageRowDraft): IMitglied[] {
    const search = this.getMitgliedControl(row).value.trim().toLowerCase();
    if (!search) {
      return this.mitglieder;
    }

    return this.mitglieder.filter((mitglied) => this.getMitgliedLabel(mitglied).toLowerCase().includes(search));
  }

  onMitgliedSelected(row: HomepageRowDraft, event: MatAutocompleteSelectedEvent): void {
    const selectedPkid = Number(event.option.value);
    const mitglied = this.mitgliederByPkid.get(selectedPkid);
    if (!mitglied) {
      return;
    }

    row.mitglied_id = selectedPkid;
    row.fallback_name = `${mitglied.vorname} ${mitglied.nachname}`.trim() || 'Nicht definiert';
    row.fallback_dienstgrad = (mitglied.dienstgrad || '').trim();
    row.fallback_photo = String(mitglied.stbnr ?? 'X');
    row.fallback_dienstgrad_img = this.resolveDienstgradImage(row.fallback_dienstgrad);

    this.getMitgliedControl(row).setValue(this.getMitgliedLabel(mitglied), { emitEvent: false });
  }

  onPhotoSelected(row: HomepageRowDraft, event: Event): void {
    const input = event.target as HTMLInputElement | null;
    const selectedFile = input?.files?.[0];

    if (!selectedFile) {
      return;
    }

    if (!selectedFile.type.startsWith('image/')) {
      this.uiMessageService.erstelleMessage('error', 'Bitte nur Bilddateien auswaehlen.');
      if (input) {
        input.value = '';
      }
      return;
    }

    const maxSizeBytes = this.apiHttpService.MaxUploadSize * 1024;
    if (selectedFile.size > maxSizeBytes) {
      this.uiMessageService.erstelleMessage('error', `Datei ist zu gross (max. ${this.apiHttpService.MaxUploadSize / 1024} MB).`);
      if (input) {
        input.value = '';
      }
      return;
    }

    this.revokePendingPhotoPreview(row.local_id);
    if (typeof URL !== 'undefined' && typeof URL.createObjectURL === 'function') {
      this.pendingPhotoPreviewUrls.set(row.local_id, URL.createObjectURL(selectedFile));
    }

    this.pendingPhotoUploads.set(row.local_id, selectedFile);
    this.pendingPhotoRemovals.delete(row.local_id);

    if (input) {
      input.value = '';
    }
  }

  removePhoto(row: HomepageRowDraft): void {
    const hadPendingUpload = this.pendingPhotoUploads.has(row.local_id);
    if (hadPendingUpload) {
      this.revokePendingPhotoPreview(row.local_id);
      this.pendingPhotoUploads.delete(row.local_id);
      if (row.photo_url) {
        this.pendingPhotoRemovals.add(row.local_id);
      } else {
        this.pendingPhotoRemovals.delete(row.local_id);
      }
      return;
    }

    if (!row.photo_url) {
      return;
    }

    this.pendingPhotoRemovals.add(row.local_id);
  }

  getPhotoPreviewUrl(row: HomepageRowDraft): string | null {
    if (this.pendingPhotoRemovals.has(row.local_id)) {
      return null;
    }

    const pendingPreviewUrl = this.pendingPhotoPreviewUrls.get(row.local_id);
    if (pendingPreviewUrl) {
      return pendingPreviewUrl;
    }

    return this.normalizePhotoUrl(row.photo_url);
  }

  hasPhotoPreview(row: HomepageRowDraft): boolean {
    return this.getPhotoPreviewUrl(row) !== null;
  }

  openPhotoPreview(row: HomepageRowDraft): void {
    const previewUrl = this.getPhotoPreviewUrl(row);
    if (!previewUrl) {
      this.uiMessageService.erstelleMessage('info', 'Kein Bild fuer die Vorschau vorhanden.');
      return;
    }

    this.focusBeforePhotoModal =
      typeof document !== 'undefined' && document.activeElement instanceof HTMLElement
        ? document.activeElement
        : null;
    this.photoModalUrl = previewUrl;
    this.photoModalOpen = true;
  }

  closePhotoPreview(): void {
    this.photoModalOpen = false;
    this.photoModalUrl = null;

    const target = this.focusBeforePhotoModal;
    this.focusBeforePhotoModal = null;
    if (target && typeof target.focus === 'function') {
      target.focus();
    }
  }

  getPhotoStatusText(row: HomepageRowDraft): string {
    const pendingFile = this.pendingPhotoUploads.get(row.local_id);
    if (pendingFile) {
      return `Neues Foto bereit: ${pendingFile.name}`;
    }

    if (this.pendingPhotoRemovals.has(row.local_id)) {
      return 'Foto wird beim Speichern entfernt.';
    }

    if (row.photo_url) {
      return 'Eigenes Foto gespeichert.';
    }

    return 'Kein eigenes Foto gespeichert.';
  }

  getMitgliedLabel(mitglied: IMitglied): string {
    const stbnr = mitglied.stbnr ?? '-';
    const rang = this.getRangText(mitglied.dienstgrad);
    return `${stbnr} - ${mitglied.vorname} ${mitglied.nachname} (${rang})`;
  }

  getRangText(dienstgrad: string | undefined): string {
    const rang = String(dienstgrad ?? '').trim();
    return rang !== '' ? rang : 'ohne Dienstgrad';
  }

  private resolveDienstgradImage(dienstgrad: string | undefined): string {
    const normalized = String(dienstgrad ?? '')
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9]/g, '');

    const map: Record<string, string> = {
      fm: 'Dgrd_fm.noe.svg',
      ofm: 'Dgrd_ofm.noe.svg',
      lm: 'Dgrd_lm.noe.svg',
      hlm: 'Dgrd_hlm.noe.svg',
      bm: 'Dgrd_bm.noe.svg',
      hbm: 'Dgrd_hbm.noe.svg',
      obi: 'Dgrd_obi.noe.svg',
      hbi: 'Dgrd_hbi.noe.svg',
      ov: 'Dgrd_ov.noe.svg',
      v: 'Dgrd_v.noe.svg',
      fkur: 'Dgrd_fkur.noe.svg',
      sb: 'Dgrd_sbea.noe.svg',
      sbea: 'Dgrd_sbea.noe.svg',
    };

    if (map[normalized]) {
      return map[normalized];
    }

    if (normalized.startsWith('e') && map[normalized.slice(1)]) {
      return map[normalized.slice(1)];
    }

    return normalized ? `Dgrd_${normalized}.noe.svg` : '';
  }

  speichern(): void {
    this.normalizeSectionsInPlace();

    if (this.sections.length === 0) {
      this.uiMessageService.erstelleMessage('error', 'Bitte mindestens eine Sektion anlegen.');
      return;
    }

    for (const section of this.sections) {
      if (!section.id || !section.title) {
        this.uiMessageService.erstelleMessage('error', 'Jede Sektion braucht eine ID und einen Titel.');
        return;
      }

      for (const row of section.members) {
        if (!row.position) {
          this.uiMessageService.erstelleMessage('error', 'Bitte alle Positionen ausfuellen.');
          return;
        }
      }
    }

    const pendingPhotoOperations = this.collectPendingPhotoOperations();

    this.loading = true;
    this.apiHttpService
      .post<IHomepageDienstposten[]>(
        this.modulBulk,
        {
          replace: true,
          rows: this.flattenRowsForSave(),
        },
        false,
      )
      .subscribe({
        next: (savedRows) => {
          const normalizedSavedRows = Array.isArray(savedRows) ? savedRows : [];
          this.executePendingPhotoOperations(normalizedSavedRows, pendingPhotoOperations).subscribe({
            next: (finalRows) => {
              try {
                this.sections = this.mapRowsToSections(finalRows);
                this.mitgliedControls.clear();
                this.clearAllPendingPhotoPreviewUrls();
                this.pendingPhotoUploads.clear();
                this.pendingPhotoRemovals.clear();
                this.closePhotoPreview();
                this.normalizeSectionsInPlace();
                this.uiMessageService.erstelleMessage('success', 'Dienstpostenplan gespeichert.');
              } catch (e: any) {
                this.uiMessageService.erstelleMessage('error', String(e));
              } finally {
                this.loading = false;
              }
            },
            error: (error: any) => {
              this.loading = false;
              this.authSessionService.errorAnzeigen(error);
            },
          });
        },
        error: (error: any) => {
          this.loading = false;
          this.authSessionService.errorAnzeigen(error);
        },
      });
  }

  private flattenRowsForSave(): IHomepageDienstposten[] {
    return this.sections.flatMap((section) =>
      section.members.map((row) => ({
        id: row.id,
        section_id: section.id,
        section_title: section.title,
        section_order: section.order,
        position: row.position,
        position_order: row.position_order,
        mitglied_id: row.mitglied_id,
        fallback_name: row.fallback_name,
        fallback_dienstgrad: row.fallback_dienstgrad,
        fallback_photo: row.fallback_photo,
        fallback_dienstgrad_img: row.fallback_dienstgrad_img,
      })),
    );
  }

  private collectPendingPhotoOperations(): PendingPhotoOperation[] {
    return this.sections.flatMap((section) =>
      section.members
        .map((row) => {
          const file = this.pendingPhotoUploads.get(row.local_id);
          const removePhoto = this.pendingPhotoRemovals.has(row.local_id);

          if (!file && !removePhoto) {
            return null;
          }

          return {
            row_key: this.createRowKey(section.id, section.order, row.position_order),
            file,
            remove_photo: removePhoto,
          } as PendingPhotoOperation;
        })
        .filter((item): item is PendingPhotoOperation => item !== null),
    );
  }

  private executePendingPhotoOperations(
    savedRows: IHomepageDienstposten[],
    operations: PendingPhotoOperation[],
  ): Observable<IHomepageDienstposten[]> {
    if (operations.length === 0 || savedRows.length === 0) {
      return of(savedRows);
    }

    const savedRowsByKey = new Map<string, IHomepageDienstposten>();
    for (const row of savedRows) {
      savedRowsByKey.set(this.createRowKey(row.section_id, row.section_order, row.position_order), row);
    }

    const updateRequests = operations
      .map((operation) => {
        const target = savedRowsByKey.get(operation.row_key);
        if (!target?.id) {
          return null;
        }

        if (operation.file) {
          const payload = new FormData();
          payload.append('photo', operation.file, operation.file.name);
          return this.apiHttpService.patch<IHomepageDienstposten>(this.modul, target.id, payload, true);
        }

        if (operation.remove_photo) {
          return this.apiHttpService.patch<IHomepageDienstposten>(this.modul, target.id, { remove_photo: true }, false);
        }

        return null;
      })
      .filter((item): item is Observable<IHomepageDienstposten> => item !== null);

    if (updateRequests.length === 0) {
      return of(savedRows);
    }

    return forkJoin(updateRequests).pipe(
      map((updatedRows) => {
        const updatedById = new Map<string, IHomepageDienstposten>();

        for (const row of savedRows) {
          if (row.id) {
            updatedById.set(String(row.id), row);
          }
        }

        for (const row of updatedRows) {
          if (row.id) {
            updatedById.set(String(row.id), row);
          }
        }

        return savedRows.map((row) => {
          if (!row.id) {
            return row;
          }
          return updatedById.get(String(row.id)) || row;
        });
      }),
    );
  }

  private createRowKey(sectionId: string, sectionOrder: number, positionOrder: number): string {
    return `${sectionId}|${sectionOrder}|${positionOrder}`;
  }

  private normalizePhotoUrl(rawValue: string | null | undefined): string | null {
    const value = String(rawValue || '').trim();
    if (!value) {
      return null;
    }

    if (value.startsWith('http://') || value.startsWith('https://') || value.startsWith('/')) {
      return value;
    }

    return `${this.apiHttpService.AppUrl}${value.replace(/^\/+/, '')}`;
  }

  private clearPendingPhotoState(row: HomepageRowDraft): void {
    this.revokePendingPhotoPreview(row.local_id);
    this.pendingPhotoUploads.delete(row.local_id);
    this.pendingPhotoRemovals.delete(row.local_id);
  }

  private revokePendingPhotoPreview(localId: string): void {
    const objectUrl = this.pendingPhotoPreviewUrls.get(localId);
    if (objectUrl && typeof URL !== 'undefined' && typeof URL.revokeObjectURL === 'function') {
      URL.revokeObjectURL(objectUrl);
    }
    this.pendingPhotoPreviewUrls.delete(localId);
  }

  private clearAllPendingPhotoPreviewUrls(): void {
    for (const objectUrl of this.pendingPhotoPreviewUrls.values()) {
      if (typeof URL !== 'undefined' && typeof URL.revokeObjectURL === 'function') {
        URL.revokeObjectURL(objectUrl);
      }
    }
    this.pendingPhotoPreviewUrls.clear();
  }
}

import { Component, Input, inject } from '@angular/core';
import { RouterLink } from '@angular/router';
import { MatToolbar } from '@angular/material/toolbar';
import { MatIconButton } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { AuthSessionService } from '../_service/auth-session.service';
import { environment } from 'src/environments/environment';

/**
 * Breadcrumb-Eintrag für `<imr-header>`.
 * Unterstützt sowohl `kuerzel`/`link` (NavigationService) als auch
 * `label`/`url` (alternative Konvention mancher Komponenten).
 */
export interface ImrBreadcrumbItem {
  /** Anzeigetext des Breadcrumb-Eintrags (primär) */
  kuerzel?: string;
  /** Anzeigetext des Breadcrumb-Eintrags (alternativ) */
  label?: string;
  /** Navigations-URL (primär) */
  link?: string | null;
  /** Navigations-URL (alternativ) */
  url?: string | null;
  /** Laufende Nummer (optional, von NavigationService gesetzt) */
  number?: number;
}

/**
 * `<imr-header>`
 *
 * Haupt-Header der Anwendung basierend auf Material Design 3 Toolbar.
 * Zeigt Logo, App-Titel, Logout-Button und optionale Breadcrumb-Navigation.
 *
 * @example
 * ```html
 * <imr-header [breadcrumb]="breadcrumb"></imr-header>
 * ```
 */
@Component({
  selector: 'imr-header',
  standalone: true,
  imports: [MatToolbar, RouterLink, MatIconButton, MatIconModule],
  template: `
    <mat-toolbar class="imr-header-toolbar">
      <a class="imr-header-logo-link" routerLink="/start" aria-label="Zur Startseite">
        <img class="imr-header-logo" src="../assets/images/icon.svg" alt="Blaulicht Cloud Logo" />
      </a>
      <a class="title imr-header-title imr-header-title-link" routerLink="/start" aria-label="Zur Startseite">
        {{ appTitle }}
      </a>
      <span class="spacer"></span>
      <button class="imr-header-logout" mat-icon-button type="button" aria-label="Abmelden" (click)="authService.abmelden()">
        <mat-icon>logout</mat-icon>
      </button>
    </mat-toolbar>

    <div class="imr-header-stepper-wrap">
      <nav class="imr-breadcrumb" aria-label="Breadcrumb">
        @if (hasBreadcrumb) {
          <a class="breadcrumb-item breadcrumb-home breadcrumb-link" aria-label="Startseite" routerLink="/start">
            <mat-icon>home</mat-icon>
          </a>

          @for (link of breadcrumb; track link; let i = $index) {
            @if (i > 0) {
              <span class="breadcrumb-separator" aria-hidden="true">&gt;</span>
              @if (link.link || link.url) {
                <a class="breadcrumb-item breadcrumb-link" [routerLink]="link.link || link.url">{{ link.kuerzel || link.label }}</a>
              } @else {
                <span class="breadcrumb-item">{{ link.kuerzel || link.label }}</span>
              }
            }
          }
        }
      </nav>
    </div>
  `,
})
export class ImrHeaderComponent {
  protected authService = inject(AuthSessionService);
  protected appTitle: string = environment.title;

  /** Breadcrumb-Einträge für die Navigationsleiste */
  @Input() breadcrumb: ImrBreadcrumbItem[] = [];

  get hasBreadcrumb(): boolean {
    return Array.isArray(this.breadcrumb) && this.breadcrumb.length > 0;
  }
}

import { Component, Input } from '@angular/core';
import { MatCardModule } from '@angular/material/card';

/**
 * `<imr-section-card>`
 *
 * Einheitliche Card-Struktur für Modul-Bereiche.
 * Kapselt eine `mat-card` mit standardisiertem Kopfbereich, optionalen
 * Card-Aktionen und einem Content-Bereich.
 *
 * @example
 * ```html
 * <imr-section-card title="Mitglieder verwalten">
 *   <div imrCardActions>
 *     <button mat-flat-button color="accent">Hinzufügen</button>
 *   </div>
 *   <!-- Karteninhalt -->
 * </imr-section-card>
 * ```
 */
@Component({
  selector: 'imr-section-card',
  standalone: true,
  imports: [MatCardModule],
  template: `
    <mat-card class="imr-card">
      @if (title) {
        <div class="imr-card__head">
          <h2>{{ title }}</h2>
          <ng-content select="[imrCardActions]"></ng-content>
        </div>
      }
      <mat-card-content class="imr-card__content">
        <ng-content></ng-content>
      </mat-card-content>
    </mat-card>
  `,
})
export class ImrSectionCardComponent {
  /** Optionaler Kartentitel (wird als <h2> im Kopfbereich gerendert) */
  @Input() title = '';
}

